import React, { useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useData } from '../../context/DataContext';

const MyTasks = () => {
  const { user } = useAuth();
  const { tasks, updateTaskProgress } = useData();
  
  // State lưu giá trị nhập mới 
  const [inputs, setInputs] = useState({});
  const [reasons, setReasons] = useState({});

  // 1. Lọc và Sắp xếp: Gấp (gần deadline) lên đầu
  const myTasks = tasks
    .filter(t => t.assigneeId === user.id)
    .sort((a, b) => new Date(a.endTime) - new Date(b.endTime));

  const handleUpdateClick = (task) => {
      const newProg = inputs[task.id] !== undefined ? parseInt(inputs[task.id]) : task.progress;
      const reason = reasons[task.id] || task.reason || '';

      // 2. Logic chặn: < 90% phải có lý do
      if (newProg < 90 && !reason.trim()) {
          alert("CẢNH BÁO: Tiến độ dưới 90% bắt buộc phải nhập lý do giải trình!");
          return;
      }

      updateTaskProgress(task.id, newProg, reason);
      alert("Cập nhật tiến độ thành công!");
  };

  return (
    <div>
      <h2 style={{ color: '#003366' }}>Nhiệm vụ của tôi</h2>
      <div style={{ display: 'grid', gap: '20px' }}>
        {myTasks.map(task => {
            const now = new Date();
            const deadline = new Date(task.endTime);
            const isOverdue = now > deadline && task.progress < 100;
            const isUrgent = !isOverdue && (deadline - now) < 86400000; // < 24h

            return (
                <div key={task.id} style={{ 
                    border: isOverdue ? '2px solid red' : (isUrgent ? '2px solid orange' : '1px solid #ccc'),
                    padding: '20px', borderRadius: '8px', background: 'white'
                }}>
                    {/* LABELS */}
                    <div style={{display:'flex', justifyContent:'space-between', alignItems:'flex-start'}}>
                        <h3 style={{margin:0, color:'#003366'}}>{task.title}</h3>
                        <div>
                            {isUrgent && <span style={{background:'orange', color:'white', padding:'4px 8px', borderRadius:'4px', marginRight:'5px', fontSize:'0.75rem', fontWeight:'bold'}}>CẦN HOÀN THÀNH GẤP</span>}
                            {isOverdue && <span style={{background:'red', color:'white', padding:'4px 8px', borderRadius:'4px', fontSize:'0.75rem', fontWeight:'bold'}}>QUÁ HẠN</span>}
                        </div>
                    </div>
                    
                    {isOverdue && <div style={{color: 'red', fontWeight: 'bold', marginTop: '10px', background:'#fff1f0', padding:'5px'}}>KỶ LUẬT ÁP DỤNG: {task.disciplineName}</div>}

                    <p style={{fontSize:'0.9rem', color:'#555'}}>
                        <strong>Check-in:</strong> {new Date(task.startTime).toLocaleString()} <br/>
                        <strong>Deadline:</strong> {new Date(task.endTime).toLocaleString()}
                    </p>
                    <p style={{fontSize:'0.9rem'}}><strong>Vai trò:</strong> {task.assignedRole} | <strong>Chi trả:</strong> {task.paymentType}</p>
                    <p style={{fontStyle:'italic', color:'#666'}}>{task.description}</p>

                    <hr style={{margin:'15px 0', borderTop:'1px solid #eee'}}/>
                    
                    {/* SLIDER DISABLED & INPUT */}
                    <label>Mức độ hoàn thành: <strong>{task.progress}%</strong></label>
                    <input type="range" min="0" max="100" value={task.progress} disabled style={{width:'100%', opacity: 0.6, margin: '10px 0'}} />
                    
                    <div style={{display: 'flex', gap: '10px', alignItems: 'center', background:'#f9fafb', padding:'10px', borderRadius:'6px'}}>
                        <span style={{fontSize:'0.9rem'}}>Nhập % mới:</span>
                        <input 
                            type="number" min="0" max="100" 
                            value={inputs[task.id] !== undefined ? inputs[task.id] : task.progress}
                            onChange={e => setInputs({...inputs, [task.id]: e.target.value})}
                            style={{padding:'5px', width: '60px', fontWeight: 'bold', border:'1px solid #ccc', borderRadius:'4px'}}
                        />
                    </div>

                    {/* REASON AREA */}
                    {((inputs[task.id] !== undefined ? inputs[task.id] : task.progress) < 90) && (
                        <div style={{marginTop:'10px'}}>
                            <div style={{color:'orange', fontSize:'0.8rem', marginBottom:'4px'}}>* Bắt buộc nhập lý do (Tiến độ &lt; 90%)</div>
                            <textarea 
                                placeholder="Giải trình lý do..."
                                value={reasons[task.id] !== undefined ? reasons[task.id] : (task.reason || '')}
                                onChange={e => setReasons({...reasons, [task.id]: e.target.value})}
                                style={{width:'100%', height:'60px', borderColor: 'orange', padding:'8px', boxSizing:'border-box'}}
                            />
                        </div>
                    )}

                    <button onClick={() => handleUpdateClick(task)} style={{marginTop:'15px', background:'#003366', color:'white', padding:'10px 20px', border:'none', borderRadius:'4px', cursor:'pointer', fontWeight:'bold'}}>
                        Cập nhật tiến độ
                    </button>
                </div>
            );
        })}
      </div>
    </div>
  );
};

export default MyTasks;
